function MyComponent() {
  const [count, setCount] = useState(0);

  // This function will be recreated on every render
  const handleIncrement = () => {
    setCount(count + 1);
  };

  // This function will be memoized and only recreated when the dependencies change
  const handleIncrementMemoized = useCallback(() => {
    setCount(count + 1);
  }, [count]);

  return (
    <div>
      <p>Count: {count}</p>
      <button onClick={handleIncrement}>Increment (recreated on every render)</button>
      <button onClick={handleIncrementMemoized}>Increment (memoized)</button>
    </div>
  );
}
